(function () {
  const modalInstances = new WeakMap();
  const collapseInstances = new WeakMap();

  function resolveTarget(trigger) {
    const selector = trigger?.getAttribute('data-bs-target') || trigger?.getAttribute('href');
    if (!selector || selector === '#') return null;
    try {
      return document.querySelector(selector);
    } catch (error) {
      return null;
    }
  }

  class Modal {
    constructor(element) {
      this.element = element;
      modalInstances.set(element, this);
    }

    show() {
      if (!this.element) return;
      this.lastActiveElement = document.activeElement instanceof HTMLElement ? document.activeElement : null;
      this.element.dispatchEvent(new CustomEvent('show.bs.modal', { bubbles: true }));
      this.element.removeAttribute('aria-hidden');
      this.element.setAttribute('aria-modal', 'true');
      this.element.setAttribute('role', 'dialog');
      this.element.classList.add('show');
      this.element.style.display = 'block';
      document.body.classList.add('modal-open');
      if (!this.element.contains(document.activeElement)) {
        this.element.focus({ preventScroll: true });
      }
      this.element.dispatchEvent(new CustomEvent('shown.bs.modal', { bubbles: true }));
    }

    hide() {
      if (!this.element) return;
      this.element.dispatchEvent(new CustomEvent('hide.bs.modal', { bubbles: true }));
      if (this.element.contains(document.activeElement)) {
        document.activeElement.blur();
      }
      this.element.classList.remove('show');
      this.element.style.display = 'none';
      this.element.setAttribute('aria-hidden', 'true');
      this.element.removeAttribute('aria-modal');
      this.element.removeAttribute('role');
      document.body.classList.remove('modal-open');
      if (this.lastActiveElement && document.contains(this.lastActiveElement)) {
        this.lastActiveElement.focus({ preventScroll: true });
      }
      this.element.dispatchEvent(new CustomEvent('hidden.bs.modal', { bubbles: true }));
    }

    static getInstance(element) {
      return modalInstances.get(element) || null;
    }

    static getOrCreateInstance(element) {
      return Modal.getInstance(element) || new Modal(element);
    }
  }

  class Collapse {
    constructor(element) {
      this.element = element;
      collapseInstances.set(element, this);
    }

    show() {
      this.element?.classList.add('show');
    }

    hide() {
      this.element?.classList.remove('show');
    }

    toggle() {
      if (!this.element) return;
      this.element.classList.toggle('show');
    }

    static getInstance(element) {
      return collapseInstances.get(element) || null;
    }

    static getOrCreateInstance(element) {
      return Collapse.getInstance(element) || new Collapse(element);
    }
  }

  function activateTab(trigger) {
    const target = resolveTarget(trigger);
    if (!target) return;
    trigger.dispatchEvent(new CustomEvent('show.bs.tab', { bubbles: true }));
    const nav = trigger.closest('.nav');
    nav?.querySelectorAll('[data-bs-toggle="tab"], [data-bs-toggle="pill"]').forEach((node) => {
      node.classList.remove('active');
      node.setAttribute('aria-selected', 'false');
    });
    const container = target.parentElement;
    container?.querySelectorAll('.tab-pane').forEach((pane) => {
      pane.classList.remove('show', 'active');
    });
    trigger.classList.add('active');
    trigger.setAttribute('aria-selected', 'true');
    target.classList.add('show', 'active');
    trigger.dispatchEvent(new CustomEvent('shown.bs.tab', { bubbles: true }));
  }

  document.addEventListener('click', (event) => {
    const modalTrigger = event.target.closest('[data-bs-toggle="modal"]');
    if (modalTrigger) {
      const target = resolveTarget(modalTrigger);
      if (target) {
        event.preventDefault();
        Modal.getOrCreateInstance(target).show();
      }
      return;
    }

    const tabTrigger = event.target.closest('[data-bs-toggle="tab"], [data-bs-toggle="pill"]');
    if (tabTrigger) {
      event.preventDefault();
      activateTab(tabTrigger);
      return;
    }

    const collapseTrigger = event.target.closest('[data-bs-toggle="collapse"]');
    if (collapseTrigger) {
      event.preventDefault();
      const target = resolveTarget(collapseTrigger);
      if (target) {
        Collapse.getOrCreateInstance(target).toggle();
      }
      return;
    }

    const dismissTrigger = event.target.closest('[data-bs-dismiss="modal"], .btn-close');
    if (dismissTrigger) {
      const modal = dismissTrigger.closest('.modal');
      if (modal) {
        event.preventDefault();
        Modal.getOrCreateInstance(modal).hide();
      }
    }
  });

  document.addEventListener('click', (event) => {
    if (event.target.classList.contains('modal')) {
      Modal.getOrCreateInstance(event.target).hide();
    }
  });

  window.bootstrap = window.bootstrap || {};
  window.bootstrap.Modal = Modal;
  window.bootstrap.Collapse = Collapse;
})();
